    if (typeof gsap !== 'undefined' && typeof ScrollTrigger !== 'undefined') {
      gsap.utils.toArray('.project-item').forEach((item, index) => {
        gsap.from(item, {
          scrollTrigger: {
            trigger: item,
            start: 'top 85%',
            toggleActions: 'play none none reverse'
          },
          duration: 0.8,
          x: index % 2 === 0 ? -50 : 50,
          opacity: 0,
          delay: index * 0.3,
          ease: 'power2.out'
        });
      });
    }
  }
